-- CBSE PUC medium quantitative (100), funbrain / quantitative. Pack: cbse_quantitative_puc100_medium.
-- Idempotent: delete this pack in quantitative, then insert.

BEGIN;

DELETE FROM public.play_questions
WHERE domain = 'funbrain'
  AND category = 'quantitative'
  AND (content->>'pack') = 'cbse_quantitative_puc100_medium';


COMMIT;
