INSERT INTO public.play_questions (domain, category, content, options, correct_answer_index, explanation)
VALUES
  ('funbrain', 'quantitative', '{"text": "Greatest number that divides 43, 91, and 183 leaving the same remainder each time?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["6", "2", "12", "4"]'::jsonb, 3, 'HCF of (91−43), (183−91), (183−43) = HCF(48, 92, 140) = 4.'),
  ('funbrain', 'quantitative', '{"text": "HCF of two numbers is 11 and LCM is 7700. If one number is 275, the other is?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["3080", "350", "308", "280"]'::jsonb, 2, 'Product of numbers = HCF×LCM → other = (11×7700)/275 = 308.'),
  ('funbrain', 'quantitative', '{"text": "Unit digit of 7^105?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["1", "9", "3", "7"]'::jsonb, 3, 'Cycle 7,9,3,1; 105 mod 4 = 1 → first in cycle → 7.'),
  ('funbrain', 'quantitative', '{"text": "If a number is divisible by both 9 and 11, it must be divisible by?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["121", "33", "99", "19"]'::jsonb, 2, '9 and 11 are coprime → divisible by their product 99.'),
  ('funbrain', 'quantitative', '{"text": "A number divided by 899 leaves remainder 63. Remainder when the same number is divided by 29?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["3", "7", "0", "5"]'::jsonb, 3, '899 = 29×31; remainder mod 29 is 63 mod 29 = 5.'),
  ('funbrain', 'quantitative', '{"text": "Sum of two numbers is 528 and their HCF is 33. How many coprime pairs (a,b) with 33a+33b=528?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["3 pairs", "2 pairs", "5 pairs", "4 pairs"]'::jsonb, 3, 'a+b=16; coprime pairs (1,15),(3,13),(5,11),(7,9) → 4.'),
  ('funbrain', 'quantitative', '{"text": "Least number divisible by 5,6,7,8 with remainder 3, and divisible by 9?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["2523", "843", "1683", "1680"]'::jsonb, 2, 'N = 840k+3; k=2 gives 1683, divisible by 9.'),
  ('funbrain', 'quantitative', '{"text": "Three bells toll every 9, 12, and 15 minutes. Next time they toll together after starting together?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["90 minutes", "60 minutes", "180 minutes (or 3 hours)", "360 minutes"]'::jsonb, 2, 'LCM(9,12,15) = 180 minutes.'),
  ('funbrain', 'quantitative', '{"text": "Total number of prime factors (with multiplicity) in 4^11 × 7^5 × 11^2?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["29", "22", "18", "31"]'::jsonb, 0, '4^11 = 2^22 → exponents sum 22+5+2 = 29.'),
  ('funbrain', 'quantitative', '{"text": "Largest 4-digit number exactly divisible by 88?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["9988", "9872", "9944", "9920"]'::jsonb, 2, '9999 mod 88 = 55 → 9999−55 = 9944.'),
  ('funbrain', 'quantitative', '{"text": "Average of 20 numbers is zero. At most, how many can be strictly greater than zero?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["18", "20", "10", "19"]'::jsonb, 3, 'At most 19 positive if one negative balances the sum to 0.'),
  ('funbrain', 'quantitative', '{"text": "Average age of 39 students is 15 years. Including teacher, average rises by 3 months. Teacher’s age?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["30 years", "24 years", "27 years", "25 years"]'::jsonb, 3, 'New mean for 40: 15.25; total increase 10 → teacher = 15 + 10 = 25.'),
  ('funbrain', 'quantitative', '{"text": "87 runs in 17th inning raises average by 3. Average after 17th inning?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["40", "36", "39", "42"]'::jsonb, 2, '16x+87=17(x+3) → x=36 → new average 39.'),
  ('funbrain', 'quantitative', '{"text": "Price decreased 25% then increased 20% on new price. Net percentage change?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["No change", "5% increase", "5% decrease", "10% decrease"]'::jsonb, 3, '100→75→90 → net −10%.'),
  ('funbrain', 'quantitative', '{"text": "Winner 55% valid votes, margin 2000; 20% votes invalid. Total voters?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["25,000", "20,000", "30,000", "22,500"]'::jsonb, 0, '10% of valid = 2000 → valid 20000; 80% of total → total 25000.'),
  ('funbrain', 'quantitative', '{"text": "Population 44,100 after 5% annual growth for 2 years. Population 2 years ago?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["38,000", "40,000", "39,600", "42,000"]'::jsonb, 1, 'P×1.05² = 44100 → P = 40000.'),
  ('funbrain', 'quantitative', '{"text": "One student scores 9 more than the other; higher score is 56% of sum of both. Marks?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["40 and 31", "45 and 36", "48 and 39", "42 and 33"]'::jsonb, 3, 'x = 0.56(2x−9) → x=42, other 33.'),
  ('funbrain', 'quantitative', '{"text": "40% needed to pass; student gets 178 and fails by 22. Maximum marks?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["400", "450", "500", "600"]'::jsonb, 2, 'Pass = 200 = 40% → max = 500.'),
  ('funbrain', 'quantitative', '{"text": "Average of 7 consecutive integers is 20. Largest?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["26", "24", "22", "23"]'::jsonb, 3, 'Middle (4th) is 20 → largest 20+3 = 23.'),
  ('funbrain', 'quantitative', '{"text": "A’s salary is 20% less than B’s. By what percent is B’s salary more than A’s?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["25%", "20%", "15%", "30%"]'::jsonb, 0, 'A=80, B=100 → (20/80)×100 = 25%.'),
  ('funbrain', 'quantitative', '{"text": "Two numbers in ratio 3:5. Subtract 9 from each → ratio 12:23. Smaller number?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["33", "36", "24", "30"]'::jsonb, 0, '(3x−9)/(5x−9)=12/23 → x=11 → smaller 33.'),
  ('funbrain', 'quantitative', '{"text": "50p, 25p, 10p coins in ratio 5:9:4; total Rs. 206. How many 10p coins?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["160", "140", "200", "120"]'::jsonb, 0, 'Value ratio 250:225:40; multiplier 40 → 10p = 4×40 = 160.'),
  ('funbrain', 'quantitative', '{"text": "Milk:water = 5:1. Add 5 L water → ratio 5:2. Milk in original mixture?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["20 liters", "15 liters", "30 liters", "25 liters"]'::jsonb, 3, 'Water part doubles (+1 part = 5 L) → 5 parts milk = 25 L.'),
  ('funbrain', 'quantitative', '{"text": "A invests Rs. 3000 for 12 months; B Rs. 4000 for 8 months. Profit Rs. 1700. A’s share?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 850", "Rs. 950", "Rs. 900", "Rs. 800"]'::jsonb, 2, 'Ratio (3000×12):(4000×8)=9:8 → A = (9/17)×1700 = 900.'),
  ('funbrain', 'quantitative', '{"text": "Divide Rs. 1250 among A,B,C: A = 2/9 of B, C = 3/4 of A. How much does A get?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 180", "Rs. 200", "Rs. 250", "Rs. 150"]'::jsonb, 1, 'A:B:C = 4:18:3 → A = (4/25)×1250 = 200.'),
  ('funbrain', 'quantitative', '{"text": "85 kg mixture milk:water 27:7. How much water to add for ratio 3:1?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["4 kg", "7.5 kg", "5 kg", "6 kg"]'::jsonb, 2, 'Milk 67.5 kg; 67.5/(17.5+w)=3 → w=5.'),
  ('funbrain', 'quantitative', '{"text": "Spirit:water in A is 5:2 and in B is 7:6. Ratio to mix A and B for spirit:water 8:5?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["5:8", "8:5", "9:7", "7:9"]'::jsonb, 3, 'Alligation on spirit fractions gives A:B = 7:9.'),
  ('funbrain', 'quantitative', '{"text": "Salaries A:B:C = 2:3:5. Increments 15%, 10%, 20%. New ratio?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["20:30:50", "21:33:55", "23:33:60", "22:32:58"]'::jsonb, 2, '200→230, 300→330, 500→600 → 23:33:60.'),
  ('funbrain', 'quantitative', '{"text": "Mean proportional between 234 and 104?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["150", "144", "156", "168"]'::jsonb, 2, '√(234×104) = √24336 = 156.'),
  ('funbrain', 'quantitative', '{"text": "Rs. divided A:B:C:D = 5:2:4:3. C gets Rs. 1000 more than D. B’s share?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 2000", "Rs. 1500", "Rs. 2500", "Rs. 1000"]'::jsonb, 0, '1 part = 1000 → B has 2 parts = 2000.'),
  ('funbrain', 'quantitative', '{"text": "Article sold for Rs. 78 at 56% profit. If sold for Rs. 60, profit %?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["25%", "20%", "10%", "15%"]'::jsonb, 1, 'CP = 78/1.56 = 50; (60−50)/50 = 20%.'),
  ('funbrain', 'quantitative', '{"text": "CP of 15 articles equals SP of 12 articles. Profit %?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["25%", "15%", "30%", "20%"]'::jsonb, 0, 'SP/CP = 15/12 → profit (3/12)×100 = 25%.'),
  ('funbrain', 'quantitative', '{"text": "Dealer sells at CP but uses 900 g for 1 kg. Profit %?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["11.11%", "10%", "12.5%", "9%"]'::jsonb, 0, 'Gain on cost of 900 g for 1000 g sold → 100/9 ≈ 11.11%.'),
  ('funbrain', 'quantitative', '{"text": "Cycle CP Rs. 1400, sold at 15% loss. SP?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 1200", "Rs. 1210", "Rs. 1190", "Rs. 1180"]'::jsonb, 2, '1400×0.85 = 1190.'),
  ('funbrain', 'quantitative', '{"text": "Sold at 2/3 of marked price → 10% loss. Profit % if sold at MP?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["30%", "40%", "35%", "25%"]'::jsonb, 2, 'MP=300 → SP at loss 200, CP=200/0.9; profit at 300 gives 35%.'),
  ('funbrain', 'quantitative', '{"text": "Successive discounts 20% and 10% equivalent single discount?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["30%", "25%", "18%", "28%"]'::jsonb, 3, '100→80→72 → 28% off.'),
  ('funbrain', 'quantitative', '{"text": "Buy 6 toffees per rupee. Sell how many per rupee for 20% gain?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["4", "5", "7", "6"]'::jsonb, 1, 'CP per piece 1/6; SP 1.2/6 = 1/5 → 5 per rupee.'),
  ('funbrain', 'quantitative', '{"text": "20% profit. Ratio CP : SP?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["5:6", "5:7", "4:5", "1:2"]'::jsonb, 0, 'CP 100, SP 120 → 5:6.'),
  ('funbrain', 'quantitative', '{"text": "Goods marked 30% above CP; discount 6.15% on MP. Gain %?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["20%", "22%", "18%", "24%"]'::jsonb, 1, 'CP 100, MP 130, disc ≈8, SP 122 → 22% gain.'),
  ('funbrain', 'quantitative', '{"text": "Profit selling at Rs. 1754 equals loss selling at Rs. 1492. CP?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 1550", "Rs. 1600", "Rs. 1650", "Rs. 1623"]'::jsonb, 3, 'CP = (1754+1492)/2 = 1623.'),
  ('funbrain', 'quantitative', '{"text": "Rate % p.a. simple interest so money doubles in 8 years?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["16%", "10%", "12.5%", "8%"]'::jsonb, 2, 'I=P requires P×R×8/100=P → R=12.5.'),
  ('funbrain', 'quantitative', '{"text": "Amount Rs. 9800 after 5 years SI and Rs. 12005 after 8 years same rate. Principal?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 6250", "Rs. 6000", "Rs. 6125", "Rs. 6500"]'::jsonb, 2, '3-year interest = 2205 → 5-year SI = 3675 → P = 9800−3675 = 6125.'),
  ('funbrain', 'quantitative', '{"text": "CI − SI for 2 years at 10% p.a. is Rs. 40. Principal?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 3500", "Rs. 3600", "Rs. 4400", "Rs. 4000"]'::jsonb, 3, 'D = P(R/100)² → 40 = P/100 → P = 4000.'),
  ('funbrain', 'quantitative', '{"text": "CI: Rs. 800 after 3 years, Rs. 840 after 4 years. Rate p.a.?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["4.5%", "5%", "6%", "4%"]'::jsonb, 1, 'Year-4 interest on 800 = 40 → 40/800 = 5%.'),
  ('funbrain', 'quantitative', '{"text": "CI on Rs. 10,000 for 2 years at 4% p.a. compounded half-yearly?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 816", "Rs. 824.32", "Rs. 800", "Rs. 832"]'::jsonb, 1, '2% per half-year, 4 periods → A=10824.32 → CI=824.32.'),
  ('funbrain', 'quantitative', '{"text": "Sum doubles in 5 years at CI. Years to become 8 times?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["12 years", "15 years", "40 years", "20 years"]'::jsonb, 1, '8 = 2³ → 3×5 = 15 years.'),
  ('funbrain', 'quantitative', '{"text": "SI for 2 years at 5% on a sum is Rs. 50. CI same sum, rate, time?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 51", "Rs. 50", "Rs. 52.50", "Rs. 51.25"]'::jsonb, 3, 'Year-2 interest on first year’s interest adds 1.25 → total CI 51.25.'),
  ('funbrain', 'quantitative', '{"text": "Present worth of Rs. 9261 due in 3 years at 5% p.a. compounded annually?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["Rs. 7800", "Rs. 8200", "Rs. 8000", "Rs. 7500"]'::jsonb, 2, 'P = 9261/(1.05)³ = 8000.'),
  ('funbrain', 'quantitative', '{"text": "Loan Rs. 1200 SI; time in years equals rate %. Interest Rs. 432. Rate?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["4%", "6%", "5%", "8%"]'::jsonb, 1, '1200×x²/100=432 → x²=36 → x=6.'),
  ('funbrain', 'quantitative', '{"text": "Sum amounts to 5/4 of itself in 5 years SI. Rate?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["4%", "6%", "10%", "5%"]'::jsonb, 3, 'I = P/4 = PR×5/100 → R=5.'),
  ('funbrain', 'quantitative', '{"text": "A in 15 days, B in 20 days. Together 4 days — fraction of work left?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["2/5", "7/15", "1/3", "8/15"]'::jsonb, 3, 'Together 7/60 per day → 4 days 7/15 done → 8/15 left.'),
  ('funbrain', 'quantitative', '{"text": "A twice as fast as B; together finish in 18 days. A alone?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["24 days", "36 days", "30 days", "27 days"]'::jsonb, 3, 'Efficiencies 2:1 → work 54 units → A 54/2 = 27 days.'),
  ('funbrain', 'quantitative', '{"text": "A+B in 12 days, B+C in 15, C+A in 20. B alone?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["20 days", "30 days", "15 days", "24 days"]'::jsonb, 0, '2(A+B+C)=1/12+1/15+1/20 → B = (A+B+C)−(C+A) = 1/20 per day.'),
  ('funbrain', 'quantitative', '{"text": "10 men finish in 7 days; 10 women in 14 days. 5 men + 10 women?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["7 days", "14 days", "5 days", "10 days"]'::jsonb, 0, '10 men = 20 women-equivalent; 5 men+10 women = 20 women-eff. → half of 14 days = 7.'),
  ('funbrain', 'quantitative', '{"text": "Pipe fills in 15 h; with leak, full in 20 h. Leak empties full tank in?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["75 hours", "60 hours", "30 hours", "45 hours"]'::jsonb, 1, '1/15 − 1/20 = 1/60 leak rate → 60 h.'),
  ('funbrain', 'quantitative', '{"text": "Pipes A and B fill in 20 and 30 minutes. Both together?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["12 minutes", "18 minutes", "15 minutes", "10 minutes"]'::jsonb, 0, '1/20+1/30 = 1/12 → 12 min.'),
  ('funbrain', 'quantitative', '{"text": "Fill 8 h, empty 5 h. Both open; tank 3/4 full. Time to empty?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["10 hours", "12 hours", "8 hours", "15 hours"]'::jsonb, 0, 'Net drain 3/40 per h; (3/4)/(3/40)=10 h.'),
  ('funbrain', 'quantitative', '{"text": "39 people, 12 days, 5 h/day. 30 people, 6 h/day — days?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["12 days", "15 days", "10 days", "13 days"]'::jsonb, 3, '39×12×5 = 30×D×6 → D=13.'),
  ('funbrain', 'quantitative', '{"text": "A takes twice B’s time and thrice C’s; together finish in 2 days. B alone?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["8 days", "9 days", "4 days", "6 days"]'::jsonb, 3, 'Times 6x:3x:2x → together rate 1/x per day, 2 days full → x=2 → B=6 days.'),
  ('funbrain', 'quantitative', '{"text": "Boy 4 L / 3 min, girl 3 L / 4 min. Time to fill 100 L together?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["36 minutes", "48 minutes", "50 minutes", "40 minutes"]'::jsonb, 1, 'Combined 25/12 L/min → 100×12/25 = 48 min.'),
  ('funbrain', 'quantitative', '{"text": "Train 60 km/h crosses a pole in 9 s. Length of train (m)?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["135 m", "160 m", "120 m", "150 meters"]'::jsonb, 3, '60×5/18 × 9 = 150 m.'),
  ('funbrain', 'quantitative', '{"text": "240 m train crosses 300 m platform in 27 s. Speed (km/h)?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["81 km/hr", "60 km/hr", "72 km/hr", "54 km/hr"]'::jsonb, 2, '540/27 = 20 m/s → 72 km/h.'),
  ('funbrain', 'quantitative', '{"text": "Two trains opposite directions: cross man in 27 s and 17 s; cross each other in 23 s. Speed ratio?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["2:3", "17:27", "3:2", "4:5"]'::jsonb, 2, 'Alligation on times: (23−17):(27−23)=6:4=3:2.'),
  ('funbrain', 'quantitative', '{"text": "Walk 5 km/h misses train by 7 min; 6 km/h reaches 5 min early. Distance (km)?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["6 km", "5 km", "8 km", "7 km"]'::jsonb, 0, 'D/5 − D/6 = 12/60 → D=6.'),
  ('funbrain', 'quantitative', '{"text": "Bus 54 km/h without stoppages, 45 km/h with. Stoppage minutes per hour?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["15 minutes", "10 minutes", "8 minutes", "12 minutes"]'::jsonb, 1, 'Lose 9 km/h worth of time at 54 km/h → (9/54)×60 = 10 min.'),
  ('funbrain', 'quantitative', '{"text": "Boat 13 km/h still water; stream 4 km/h. Time for 68 km downstream?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["5 hours", "3.5 hours", "4 hours", "4.5 hours"]'::jsonb, 2, '17 km/h → 68/17 = 4 h.'),
  ('funbrain', 'quantitative', '{"text": "Upstream 8 km/h, downstream 13 km/h. Stream speed?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["2 km/hr", "3 km/hr", "2.5 km/hr", "3.5 km/hr"]'::jsonb, 2, '(13−8)/2 = 2.5 km/h.'),
  ('funbrain', 'quantitative', '{"text": "100 m race: A in 36 s, B in 45 s. By how many meters does A beat B?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["10 m", "25 m", "15 m", "20 meters"]'::jsonb, 3, 'B runs 80 m in 36 s → margin 20 m.'),
  ('funbrain', 'quantitative', '{"text": "125 m train passes man running 5 km/h same direction in 10 s. Train speed?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["50 km/hr", "48 km/hr", "45 km/hr", "55 km/hr"]'::jsonb, 0, 'Rel 12.5 m/s = 45 km/h; train = 45+5 = 50 km/h.'),
  ('funbrain', 'quantitative', '{"text": "Sound 330 m/s; thunder 5 s after lightning. Storm distance?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["1500 m", "1650 meters", "1800 m", "1320 m"]'::jsonb, 1, '330×5 = 1650 m.'),
  ('funbrain', 'quantitative', '{"text": "Arrangements of LEADING with vowels E,A,I always together?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["1440", "360", "600", "720"]'::jsonb, 3, 'Block of 3 vowels + 4 consonants → 5!×3! = 720.'),
  ('funbrain', 'quantitative', '{"text": "7 consonants, 4 vowels: words with 3 consonants and 2 vowels?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["21,000", "18,900", "25,200", "30,240"]'::jsonb, 2, '⁷C₃×⁴C₂×5! = 35×6×120 = 25200.'),
  ('funbrain', 'quantitative', '{"text": "Groups of 5 men and 2 women from 7 men and 3 women?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["105", "35", "63", "42"]'::jsonb, 2, '⁷C₅×³C₂ = 21×3 = 63.'),
  ('funbrain', 'quantitative', '{"text": "3-digit numbers from 2,3,5,6,7,9, no repeat, divisible by 5?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["15", "20", "30", "24"]'::jsonb, 1, 'Unit digit 5 fixed; first two from 5 remaining digits → 5×4 = 20.'),
  ('funbrain', 'quantitative', '{"text": "Committee of 3 from 3 men and 4 women with at least one woman?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["31", "34", "35", "33"]'::jsonb, 1, '⁷C₃ − ³C₃ = 35−1 = 34.'),
  ('funbrain', 'quantitative', '{"text": "Diagonals in a 12-sided convex polygon?", "pack": "cbse_quantitative_puc100_medium"}'::jsonb, '["48", "66", "60", "54"]'::jsonb, 3, 'n(n−3)/2 = 12×9/2 = 54.'),
